import React, { useEffect, useState, useCallback } from 'react';
import { useSearchParams } from 'react-router-dom';
import api from '../utils/api';
import ProductCard from '../components/ProductCard';

export default function ShopPage() {
  const [searchParams, setSearchParams] = useSearchParams();
  const [products, setProducts]   = useState([]);
  const [categories, setCategories] = useState([]);
  const [brands, setBrands]       = useState([]);
  const [total, setTotal]         = useState(0);
  const [pages, setPages]         = useState(1);
  const [loading, setLoading]     = useState(true);
  const [filterOpen, setFilterOpen] = useState(true);

  const page     = parseInt(searchParams.get('page') || 1);
  const sort     = searchParams.get('sort')      || 'created_at';
  const order    = searchParams.get('order')     || 'desc';
  const category = searchParams.get('category') || '';
  const brand    = searchParams.get('brand')    || '';
  const search   = searchParams.get('search')   || '';
  const minPrice = searchParams.get('min_price')|| '';
  const maxPrice = searchParams.get('max_price')|| '';
  const featured = searchParams.get('featured') || '';
  const newArr   = searchParams.get('new_arrival') || '';
  const inStock  = searchParams.get('in_stock')  || '';

  const setParam = (key, val) => {
    const p = new URLSearchParams(searchParams);
    val ? p.set(key, val) : p.delete(key);
    p.set('page', 1);
    setSearchParams(p);
  };

  const fetchProducts = useCallback(async () => {
    setLoading(true);
    try {
      const q = new URLSearchParams({ page, sort, order, limit: 12 });
      if (category) q.set('category', category);
      if (brand)    q.set('brand', brand);
      if (search)   q.set('search', search);
      if (minPrice) q.set('min_price', minPrice);
      if (maxPrice) q.set('max_price', maxPrice);
      if (featured) q.set('featured', featured);
      if (newArr)   q.set('new_arrival', newArr);
      if (inStock)  q.set('in_stock', inStock);
      const res = await api.get(`/products?${q}`);
      setProducts(res.data.products);
      setTotal(res.data.total);
      setPages(res.data.pages);
    } catch {} finally { setLoading(false); }
  }, [page, sort, order, category, brand, search, minPrice, maxPrice, featured, newArr, inStock]);

  useEffect(() => {
    fetchProducts();
    api.get('/categories').then(r => setCategories(r.data.categories)).catch(() => {});
    api.get('/brands').then(r => setBrands(r.data.brands)).catch(() => {});
  }, [fetchProducts]);

  useEffect(() => {
    document.title = `Shop${search ? ` — "${search}"` : ''} — LUXE`;
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [page, search]);

  const hasFilters = category || brand || search || minPrice || maxPrice || featured || newArr || inStock;

  const priceRanges = [
    ['Under ₹1,000', '', '1000'], ['₹1,000–₹3,000', '1000', '3000'],
    ['₹3,000–₹6,000', '3000', '6000'], ['₹6,000–₹10,000', '6000', '10000'],
    ['Above ₹10,000', '10000', ''],
  ];

  const FilterChip = ({ label, active, onClick }) => (
    <button onClick={onClick}
      className={`mr-2 mb-2 px-3 py-1.5 text-xs border transition-all duration-200
        ${active ? 'border-luxury-black bg-luxury-black text-white' : 'border-gray-200 text-gray-600 hover:border-gray-400 hover:text-luxury-black'}`}>
      {label}
    </button>
  );

  const SectionTitle = ({ children }) => (
    <h4 className="text-[10px] font-semibold tracking-[2px] uppercase text-gray-400 mb-3">{children}</h4>
  );

  return (
    <div className="max-w-screen-xl mx-auto px-6 py-8">
      {/* Header */}
      <div className="flex items-center justify-between pb-6 border-b border-gray-200 mb-8">
        <div>
          <h1 className="font-serif text-3xl">
            {search ? `Results for "${search}"` : category ? category.charAt(0).toUpperCase() + category.slice(1) : 'All Products'}
          </h1>
          {!loading && <p className="text-sm text-gray-400 mt-1">{total.toLocaleString()} products</p>}
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setFilterOpen(!filterOpen)}
            className="btn btn-ghost btn-sm flex items-center gap-2">
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" strokeWidth={1.5} viewBox="0 0 24 24">
              <path d="M3 6h18M7 12h10M11 18h2"/>
            </svg>
            {filterOpen ? 'Hide' : 'Show'} Filters
          </button>
          <select className="form-select text-xs py-2 w-auto"
            value={`${sort}:${order}`}
            onChange={e => { const [s,o] = e.target.value.split(':'); setParam('sort',s); setParam('order',o); }}>
            {[
              ['Featured',        'is_featured:desc'],
              ['Newest',          'created_at:desc'],
              ['Price: Low–High', 'price:asc'],
              ['Price: High–Low', 'price:desc'],
              ['Top Rated',       'avg_rating:desc'],
              ['Best Selling',    'sold_count:desc'],
            ].map(([l, v]) => <option key={v} value={v}>{l}</option>)}
          </select>
        </div>
      </div>

      <div className="flex gap-8 items-start">
        {/* Filters */}
        {filterOpen && (
          <aside className="w-56 flex-shrink-0 sticky top-24 space-y-6">
            {hasFilters && (
              <div className="bg-amber-50 border border-amber-100 p-3 flex items-center justify-between">
                <span className="text-[11px] text-amber-700 font-medium">Filters active</span>
                <button onClick={() => setSearchParams({})} className="text-[11px] text-red-500 hover:text-red-700 underline">Clear all</button>
              </div>
            )}

            <div className="border-b border-gray-100 pb-5">
              <SectionTitle>Categories</SectionTitle>
              <div className="flex flex-wrap">
                <FilterChip label="All" active={!category} onClick={() => setParam('category', '')} />
                {categories.map(c => (
                  <FilterChip key={c.id} label={c.name} active={category === c.slug}
                    onClick={() => setParam('category', category === c.slug ? '' : c.slug)} />
                ))}
              </div>
            </div>

            <div className="border-b border-gray-100 pb-5">
              <SectionTitle>Price Range</SectionTitle>
              <div className="flex flex-wrap">
                {priceRanges.map(([label, min, max]) => (
                  <FilterChip key={label} label={label}
                    active={minPrice === min && maxPrice === max}
                    onClick={() => { setParam('min_price', min); setParam('max_price', max); }}
                  />
                ))}
              </div>
            </div>

            <div className="border-b border-gray-100 pb-5">
              <SectionTitle>Brands</SectionTitle>
              <div className="flex flex-wrap">
                {brands.slice(0, 8).map(b => (
                  <FilterChip key={b.id} label={b.name} active={brand === b.slug}
                    onClick={() => setParam('brand', brand === b.slug ? '' : b.slug)} />
                ))}
              </div>
            </div>

            <div>
              <SectionTitle>Collections</SectionTitle>
              <div className="flex flex-wrap">
                <FilterChip label="New Arrivals" active={newArr === 'true'} onClick={() => setParam('new_arrival', newArr === 'true' ? '' : 'true')} />
                <FilterChip label="Featured"     active={featured === 'true'} onClick={() => setParam('featured', featured === 'true' ? '' : 'true')} />
                <FilterChip label="In Stock"     active={inStock === 'true'} onClick={() => setParam('in_stock', inStock === 'true' ? '' : 'true')} />
              </div>
            </div>
          </aside>
        )}

        {/* Grid */}
        <div className="flex-1 min-w-0">
          {loading ? (
            <div className="flex items-center justify-center py-32">
              <div className="spinner spinner-lg spinner-gold" />
            </div>
          ) : products.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-24 text-center">
              <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center text-3xl mb-4">🔍</div>
              <h3 className="font-serif text-xl mb-2">No products found</h3>
              <p className="text-sm text-gray-400 mb-6">Try adjusting your filters or search term</p>
              <button onClick={() => setSearchParams({})} className="btn btn-primary">Clear All Filters</button>
            </div>
          ) : (
            <>
              <div className={`grid gap-5 ${filterOpen ? 'grid-cols-2 md:grid-cols-3' : 'grid-cols-2 md:grid-cols-3 lg:grid-cols-4'}`}>
                {products.map(p => <ProductCard key={p.id} product={p} />)}
              </div>

              {/* Pagination */}
              {pages > 1 && (
                <div className="flex items-center justify-center gap-2 mt-12">
                  <button disabled={page <= 1} onClick={() => setParam('page', page - 1)}
                    className="w-9 h-9 flex items-center justify-center border border-gray-200 hover:border-luxury-black hover:bg-luxury-black hover:text-white transition-all disabled:opacity-30 disabled:cursor-not-allowed text-sm">
                    ←
                  </button>
                  {Array.from({ length: Math.min(pages, 7) }, (_, i) => i + 1).map(p => (
                    <button key={p} onClick={() => setParam('page', p)}
                      className={`w-9 h-9 flex items-center justify-center border text-sm transition-all
                        ${page === p ? 'border-luxury-black bg-luxury-black text-white' : 'border-gray-200 hover:border-gray-400'}`}>
                      {p}
                    </button>
                  ))}
                  <button disabled={page >= pages} onClick={() => setParam('page', page + 1)}
                    className="w-9 h-9 flex items-center justify-center border border-gray-200 hover:border-luxury-black hover:bg-luxury-black hover:text-white transition-all disabled:opacity-30 disabled:cursor-not-allowed text-sm">
                    →
                  </button>
                </div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
}
